# policies/claude-provisioning.rego
package claude.provisioning

import future.keywords.if

# Deny if requested TPM exceeds the team's pre-approved quota
deny[msg] if {
    input.requested_tpm > data.quota_limits[input.owner_team].max_tpm_per_env
    msg := sprintf(
        "Requested TPM %d exceeds team quota %d. Request a quota increase via #platform.",
        [input.requested_tpm, data.quota_limits[input.owner_team].max_tpm_per_env]
    )
}

# Deny if monthly cost cap exceeds team budget
deny[msg] if {
    input.environment_type != "development"   # dev envs have no cap
    input.cost_cap_monthly_usd > data.cost_limits[input.owner_team].max_monthly_usd
    msg := sprintf(
        "Requested cost cap $%d exceeds team budget $%d.",
        [input.cost_cap_monthly_usd, data.cost_limits[input.owner_team].max_monthly_usd]
    )
}

# Deny load-test environments > 4 hours
deny[msg] if {
    input.environment_type == "load-test"
    input.ttl_hours > 4
    msg := "Load-test environments have a maximum TTL of 4 hours."
}

# Deny if integration_name is not registered in the catalog
deny[msg] if {
    not data.catalog_components[input.integration_name]
    msg := sprintf(
        "Integration '%s' is not registered in the service catalog. Register it first.",
        [input.integration_name]
    )
}

# modules/claude-environment/main.tf
variable "integration_name" { type = string }
variable "environment_type" { type = string }
variable "owner_team"        { type = string }
variable "cost_cap_monthly_usd" { type = number }
variable "requested_tpm"    { type = number }
variable "requested_rpm"    { type = number }

# Create a dedicated secret for this environment's API key
resource "aws_secretsmanager_secret" "api_key" {
  name        = "/claude/${var.environment_type}/${var.integration_name}/anthropic-key"
  description = "Anthropic API key for ${var.integration_name} (${var.environment_type})"
  tags = {
    integration = var.integration_name
    environment = var.environment_type
    owner_team  = var.owner_team
    managed_by  = "idp-provisioning"
  }
}

# The actual API key value is set by the secrets rotation lambda,
# not by Terraform (to avoid storing the key in Terraform state)
resource "aws_secretsmanager_secret_version" "api_key_placeholder" {
  secret_id     = aws_secretsmanager_secret.api_key.id
  secret_string = jsonencode({ status = "pending-rotation" })
  lifecycle { ignore_changes = [secret_string] }
}

# Rate limit allocation in the internal rate-limit service
resource "internal_rate_limit_allocation" "quota" {
  service_name = "${var.integration_name}-${var.environment_type}"
  tpm          = var.requested_tpm
  rpm          = var.requested_rpm
  owner_team   = var.owner_team
}

# Cost budget in the cost monitoring service
resource "internal_cost_budget" "monthly" {
  service_name           = "${var.integration_name}-${var.environment_type}"
  monthly_cap_usd        = var.cost_cap_monthly_usd
  alert_threshold_pct    = 80
  alert_channel          = "#${var.owner_team}-costs"
  hard_stop_at_cap       = var.environment_type != "development"
}

# Grafana dashboard from template
resource "grafana_dashboard" "claude_env" {
  config_json = templatefile("${path.module}/dashboard-template.json", {
    service_name = "${var.integration_name}-${var.environment_type}"
    environment  = var.environment_type
  })
  folder = "Claude Integrations"
}

output "api_key_secret_arn"   { value = aws_secretsmanager_secret.api_key.arn }
output "dashboard_url"        { value = grafana_dashboard.claude_env.url }
output "rate_limit_quota_id"  { value = internal_rate_limit_allocation.quota.id }
